noncompliant:
void test(char c) {
  switch (c) {
    case 2000: // Noncompliant - 2000 exceeds char range (-128 to 127)
      break;
  }
}

unsigned char add_overflow() {
  unsigned char a = 250;
  unsigned char b = 10;
  return a + b; // Noncompliant - overflows to 4
}

int multiply_overflow() {
  int x = 2000000000;
  int y = 2;
  return x * y; // Noncompliant - signed overflow (undefined behavior)
}

compliant:
void test(int c) {
  switch (c) {
    case 2000: // Compliant - int can hold 2000
      break;
  }
}

#include <limits>
unsigned char safe_add(unsigned char a, unsigned char b) {
  if (a > std::numeric_limits<unsigned char>::max() - b) {
    // Handle overflow
    return std::numeric_limits<unsigned char>::max();
  }
  return a + b; // Compliant
}

#include <limits>
int safe_multiply(int x, int y) {
  if (x > 0 && y > std::numeric_limits<int>::max() / x) {
    // Handle overflow
    return std::numeric_limits<int>::max();
  }
  return x * y; // Compliant
}
